"""Snapshot regression tests — current output must match frozen CSVs.

Ref: docs/specs/test-strategy.md Section 2.1
Requirement: same seed + same config = byte-identical CSV output.

Fixtures generated by: generate_fixtures.py (seed=42, 1 day, 5min freq)
"""
from __future__ import annotations

import csv
from pathlib import Path

import numpy as np
import pandas as pd
import pytest

from synthetic_generator.core.pv import build_pvn
from synthetic_generator.domains.registry import auto_discover_domains, get_domain

SEED = 42
FREQ = "5min"
TZ = "Europe/Madrid"
START = "2026-01-01"
END = "2026-01-01"

FIXTURES_DIR = Path(__file__).resolve().parent.parent / "fixtures"

CSV_COLUMNS = [
    "timestamp", "domain_id", "site_id", "asset_id", "variable",
    "value", "unit", "data_type", "point_type", "quality", "origin", "pvn",
]


def _format_value(value):
    if value is None:
        return ""
    if isinstance(value, bool):
        return str(int(value))
    if isinstance(value, float):
        return str(round(value, 4))
    return str(value)


def _generate_domain_rows(domain_id: str, project_cfg: dict, domain_cfg: dict) -> list[dict]:
    """Generate CSV rows for a domain (same logic as generate_fixtures.py)."""
    auto_discover_domains()
    plugin = get_domain(domain_id)

    time_index = pd.date_range(START, f"{END} 23:55", freq=FREQ, tz=TZ)
    rng = np.random.default_rng(SEED)

    inventory = plugin.build_inventory(project_cfg, domain_cfg)
    ctx = plugin.build_context(time_index, project_cfg, domain_cfg, rng)

    rng = np.random.default_rng(SEED)
    points_iter = plugin.simulate(time_index, inventory, ctx, rng)

    rows = []
    for point in points_iter:
        ts = point.timestamp.isoformat() if hasattr(point.timestamp, 'isoformat') else str(point.timestamp)
        rows.append({
            "timestamp": ts,
            "domain_id": point.domain_id,
            "site_id": point.site_id,
            "asset_id": point.asset_id,
            "variable": point.variable,
            "value": _format_value(point.value),
            "unit": point.unit,
            "data_type": point.data_type.value if hasattr(point.data_type, 'value') else point.data_type,
            "point_type": point.point_type.value if hasattr(point.point_type, 'value') else point.point_type,
            "quality": point.quality.value if hasattr(point.quality, 'value') else point.quality,
            "origin": point.origin,
            "pvn": build_pvn(point.asset_id, point.variable),
        })
    return rows


def _load_fixture_rows(filename: str) -> list[dict]:
    """Load fixture CSV into list of dicts."""
    path = FIXTURES_DIR / filename
    if not path.exists():
        pytest.skip(f"Fixture not found: {path}")
    with open(path, "r", encoding="utf-8") as f:
        reader = csv.DictReader(f)
        return list(reader)


def _compare_rows(generated: list[dict], expected: list[dict], domain_id: str):
    """Compare generated rows against fixture rows."""
    assert len(generated) == len(expected), (
        f"{domain_id}: row count mismatch: generated={len(generated)}, expected={len(expected)}"
    )

    mismatches = []
    for i, (gen, exp) in enumerate(zip(generated, expected)):
        for col in CSV_COLUMNS:
            g = str(gen.get(col, ""))
            e = str(exp.get(col, ""))
            if g != e:
                mismatches.append(f"  row {i}, col '{col}': generated={g!r}, expected={e!r}")
                if len(mismatches) >= 10:
                    break
        if len(mismatches) >= 10:
            break

    assert len(mismatches) == 0, (
        f"{domain_id}: {len(mismatches)} mismatches (showing first 10):\n" + "\n".join(mismatches)
    )


@pytest.mark.snapshot
class TestSnapshotRegression:
    """Output must match frozen CSV snapshots generated with seed=42."""

    def test_bms_classrooms_snapshot(self):
        """BMS Classrooms output matches ies_simarro_seed42_1day.csv."""
        expected = _load_fixture_rows("ies_simarro_seed42_1day.csv")
        generated = _generate_domain_rows(
            domain_id="bms_classrooms",
            project_cfg={"namespace": "captia", "site_id": "ies_simarro"},
            domain_cfg={"n_aulas": 3},
        )
        _compare_rows(generated, expected, "bms_classrooms")

    # CAPTIA-SYNTHETIC-DATA-BMS: industrial_refrigeration & discrete_manufacturing
    # snapshots removed (vendor slimmed to BMS only). See PATCHES/001-bms-only.patch.
